        "content": "type: code\napp_id: code\nskill_id: code\nlanguage: javascript\ncode: \"// Get today's date string in YYYY-MM-DD format based on local time\\nconst getTodayStr = () => {\\n  const d = new Date();\\n  d.setMinutes(d.getMinutes() - d.getTimezoneOffset());\\n  return d.toISOString().split('T')[0];\\n};\\n\\nconst todayStr = getTodayStr();\\n\\n// Load habits from LocalStorage or initialize an empty array\\nlet habits = JSON.parse(localStorage.getItem('habitGarden_habits')) || [];\\n\\n// Save state to LocalStorage\\nfunction saveHabits() {\\n  localStorage.setItem('habitGarden_habits', JSON.stringify(habits));\\n}\\n\\n// Generate the last 7 days for the garden view\\nfunction getPast7Days() {\\n  const days = [];\\n  for (let i = 6; i >= 0; i--) {\\n    const d = new Date();\\n    d.setDate(d.getDate() - i);\\n    // Correctly adjust for local timezone\\n    d.setMinutes(d.getMinutes() - d.getTimezoneOffset());\\n    days.push(d.toISOString().split('T')[0]);\\n  }\\n  return days;\\n}\\n\\n// Map habit indices to different flowers\\nconst flowerTypes = ['🌻', '🌷', '🌹', '🌼', '🌸', '🌺', '🏵️'];\\n\\n// Main Render Function\\nfunction render() {\\n  renderTodayList();\\n  renderGarden();\\n}\\n\\n// Toggle completion status for today\\nfunction toggleHabitToday(id) {\\n  const habit = habits.find(h => h.id === id);\\n  if (habit) {\\n    habit.records[todayStr] = !habit.records[todayStr];\\n    saveHabits();\\n    render();\\n  }\\n}\\n\\n// Delete a habit entirely\\nfunction deleteHabit(id) {\\n  if (confirm('Are you sure you want to uproot this habit forever?')) {\\n    habits = habits.filter(h => h.id !== id);\\n    saveHabits();\\n    render();\\n  }\\n}\\n\\n// Render the actionable \\\"Today's Tasks\\\" list\\nfunction renderTodayList() {\\n  const container = document.getElementById('today-list');\\n  container.innerHTML = '';\\n\\n  if (habits.length === 0) {\\n    container.innerHTML = '<div class=\\\"empty-state\\\">No seeds planted yet. Add a habit above to start your garden!</div>';\\n    return;\\n  }\\n\\n  habits.forEach(habit => {\\n    const isDone = !!habit.records[todayStr];\\n    \\n    const div = document.createElement('div');\\n    div.className = `habit-item ${isDone ? 'done' : ''}`;\\n\\n    const label = document.createElement('div');\\n    label.className = 'habit-name';\\n    label.textContent = habit.name;\\n\\n    const actions = document.createElement('div');\\n    actions.className = 'action-buttons';\\n    \\n    const waterBtn = document.createElement('button');\\n    waterBtn.className = 'btn-water';\\n    waterBtn.textContent = isDone ? 'Undo' : '💧 Water';\\n    waterBtn.onclick = () => toggleHabitToday(habit.id);\\n\\n    const delBtn = document.createElement('button');\\n    delBtn.className = 'btn-delete';\\n    delBtn.textContent = '✖';\\n    delBtn.title = 'Delete Habit';\\n    delBtn.onclick = () => deleteHabit(habit.id);\\n\\n    actions.appendChild(waterBtn);\\n    actions.appendChild(delBtn);\\n\\n    div.appendChild(label);\\n    div.appendChild(actions);\\n    container.appendChild(div);\\n  });\\n}\\n\\n// Render the 7-day visualization grid\\nfunction renderGarden() {\\n  const container = document.getElementById('garden-container');\\n  container.innerHTML = '';\\n\\n  if (habits.length === 0) return;\\n\\n  const days = getPast7Days();\\n\\n  // Create Header for Dates\\n  const header = document.createElement('div');\\n  header.className = 'day-labels';\\n  days.forEach(d => {\\n    const span = document.createElement('div');\\n    span.className = 'day-label';\\n    // Format to MM/DD\\n    span.textContent = d.slice(5, 10).replace('-', '/');\\n    header.appendChild(span);\\n  });\\n  container.appendChild(header);\\n\\n  // Create Grid\\n  const grid = document.createElement('div');\\n  grid.className = 'garden-grid';\\n\\n  habits.forEach((habit, index) => {\\n    const row = document.createElement('div');\\n    row.className = 'garden-row';\\n\\n    const label = document.createElement('div');\\n    label.className = 'garden-label';\\n    label.textContent = habit.name;\\n    label.title = habit.name;\\n    row.appendChild(label);\\n\\n    const dayContainer = document.createElement('div');\\n    dayContainer.className = 'garden-days';\\n\\n    const flowerEmoji = flowerTypes[index % flowerTypes.length];\\n\\n    days.forEach(day => {\\n      const plot = document.createElement('div');\\n      const isDone = habit.records[day];\\n      \\n      if (isDone) {\\n        plot.className = 'garden-plot bloomed';\\n        plot.textContent = flowerEmoji;\\n        plot.title = `${day}: Bloomed!`;\\n      } else {\\n        plot.className = 'garden-plot planted';\\n        plot.textContent = '🌱'; // Seedling for missed/unwatered days\\n        plot.title = `${day}: Needs watering`;\\n      }\\n      dayContainer.appendChild(plot);\\n    });\\n\\n    row.appendChild(dayContainer);\\n    grid.appendChild(row);\\n  });\\n\\n  container.appendChild(grid);\\n}\\n\\n// Event Listeners for Adding Habits\\ndocument.getElementById('add-habit-btn').addEventListener('click', () => {\\n  const input = document.getElementById('new-habit-input');\\n  const name = input.value.trim();\\n  \\n  if (name) {\\n    habits.push({\\n      id: Date.now().toString(),\\n      name,\\n      records: {} // Format: { \\\"YYYY-MM-DD\\\": true }\\n    });\\n    saveHabits();\\n    input.value = '';\\n    render();\\n  }\\n});\\n\\ndocument.getElementById('new-habit-input').addEventListener('keypress', (e) => {\\n  if (e.key === 'Enter') {\\n    document.getElementById('add-habit-btn').click();\\n  }\\n});\\n\\n// Kick off initial rendering\\nrender();\\n\"\nfilename: src/main.js\nembed_ref: src-main.js-c1c323\nstatus: finished\nline_count: 190",
